import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import moment from "moment";
import Navigation from "./components/navigation/Navigation";
import Landing from "./routes/landing/Landing";
import Footer from "./components/footer/Footer";
import Contact from "./routes/contact/Contact";
import Pricing from "./routes/pricing/Pricing";
import Faq from "./routes/faq/Faq";
import Blog from "./routes/blog/Blog";
import About from "./routes/about/About";
import Terms from "./routes/terms/Terms";
import Refunds from "./routes/refunds/Refunds";
import Privacy from "./routes/privacy/Privacy";
import Jobs from "./routes/jobs/Jobs";
import SignIn from "./routes/sign-in/SignIn";
import SignUp from "./routes/sign-up/SignUp";
import BlogPost from "./routes/blog-post/BlogPost";
import edgyBase from "./airtable/airtable";
import { useEffect, useState } from "react";
import { v4 as uuidv4 } from "uuid";
import Profile from "./routes/user-profile/Profile";
import NotFound from "./components/NotFound";

export default function App() {
  const [user, setUser] = useState(null);
  const [loggedIn, setLoggedIn] = useState(false);
  const [triggeredLogout, setTriggeredLogout] = useState(false);

  useEffect(() => {
    if (
      loggedIn &&
      sessionStorage.getItem("loggedIn") === null &&
      !triggeredLogout
    ) {
      sessionStorage.setItem("loggedIn", "true");
    }
    if (triggeredLogout && sessionStorage.getItem("loggedIn") !== null) {
      sessionStorage.removeItem("loggedIn");
      sessionStorage.removeItem("user");
    }
    if (sessionStorage.getItem("loggedIn") !== null && !triggeredLogout) {
      setLoggedIn(true);
      const jsonUser = sessionStorage.getItem("user");
      if (jsonUser) {
        setUser(JSON.parse(jsonUser));
      }
    }
  }, [loggedIn, triggeredLogout]);

  useEffect(() => {
    const jsonUser = sessionStorage.getItem("user");
    if (jsonUser) {
      const userData = JSON.parse(jsonUser);
      setUser(userData);
      setLoggedIn(true);
    }
  }, []);

  const findUserByEmail = (records, email) =>
    records.find((record) => record.fields.email === email);

  const retrieveDatabase = async (email, password = undefined) => {
    try {
      const response = await fetch(import.meta.env.VITE_AIRTABLE_SERVER_URL);
      const data = await response.json();

      if (data) {
        const userByEmail = findUserByEmail(data.records, email);
        if (userByEmail) {
          if (loggedIn && userByEmail.fields.email === user.email) {
            return true;
          }
          if (userByEmail.fields.password === password) {
            const userData = {
              id: userByEmail.id,
              createdTime: moment(userByEmail.createdTime)
                .utc()
                .format("YYYY-MM-DD"),
              email: userByEmail.fields.email,
              fullname: userByEmail.fields.fullname,
              gender: userByEmail.fields.gender,
              plan: userByEmail.fields.plan,
              password: userByEmail.fields.password,
            };

            setUser(userData);
            sessionStorage.setItem("user", JSON.stringify(userData));

            return true;
          }
          return true;
        } else {
          return false;
        }
      }
    } catch (err) {
      return false;
    }
  };
  const userEmailExists = async (email) => {
    try {
      const user = await retrieveDatabase(email.toLowerCase());
      return !!user;
    } catch (error) {
      console.log("Failed to check user existence:", error);
      return false;
    }
  };
  const registerUser = async (data) => {
    const { email, password, fullname } = data;
    const id = uuidv4();
    const checkUser = await userEmailExists(data.email);

    if (checkUser) {
      return false;
    } else {
      try {
        edgyBase("users").create([
          {
            fields: {
              id: id,
              email: email.toLowerCase(),
              password: password,
              fullname: fullname,
            },
          },
        ]);
        return true;
      } catch (error) {
        console.error(error);
      }
    }
  };

  const updateUser = async (userId, formValue) => {
    const key = Object.keys(formValue)[0];
    const value = Object.values(formValue)[0];
    if (key === "email") {
      let checkUser = await userEmailExists(value);
      if (checkUser) return { success: false, reason: "email" };
    }

    try {
      const response = await fetch(import.meta.env.VITE_AIRTABLE_SERVER_URL, {
        method: "POST",
        headers: {
          "content-type": "application/json",
        },
        body: JSON.stringify({ userId, formValue }),
      });
      const result = await response.json();
      if (!result.success) return { success: false, reason: result.reason };

      setUser({ ...user, [key]: value });
      sessionStorage.setItem("user", JSON.stringify({ ...user, [key]: value }));
      return { success: true };
    } catch (error) {
      return { success: false, reason: error };
    }
  };

  const deleteUser = (userId) => {
    edgyBase("users").destroy([userId], function (err, deletedRecords) {
      if (err) {
        console.error(err);
        return;
      }
    });
    setLoggedIn(false);
  };

  return (
    <Router>
      <Navigation
        loggedIn={loggedIn}
        setLoggedIn={setLoggedIn}
        setTriggeredLogout={setTriggeredLogout}
      />
      <Routes>
        <Route path="/" element={<Landing loggedIn={loggedIn} />} />
        <Route path="/contact" element={<Contact />} />
        <Route path="/pricing" element={<Pricing loggedIn={loggedIn} />} />
        <Route path="/faq" element={<Faq />} />
        <Route path="/blog" element={<Blog />} />
        <Route path="/blog/:name" element={<BlogPost />} />
        <Route path="/about" element={<About />} />
        <Route path="/terms" element={<Terms />} />
        <Route path="/refunds" element={<Refunds />} />
        <Route path="/privacy" element={<Privacy />} />
        <Route path="/jobs" element={<Jobs />} />
        <Route
          path="/sign-in"
          element={
            loggedIn ? (
              <Profile
                retrieveDatabase={retrieveDatabase}
                user={user}
                updateUser={updateUser}
                deleteUser={deleteUser}
                setLoggedIn={setLoggedIn}
                setTriggeredLogout={setTriggeredLogout}
              />
            ) : (
              <SignIn
                retrieveDatabase={retrieveDatabase}
                user={user}
                setLoggedIn={setLoggedIn}
              />
            )
          }
        />
        <Route
          path="/sign-up"
          element={
            loggedIn ? (
              <Profile
                retrieveDatabase={retrieveDatabase}
                user={user}
                updateUser={updateUser}
                deleteUser={deleteUser}
                setLoggedIn={setLoggedIn}
                setTriggeredLogout={setTriggeredLogout}
              />
            ) : (
              <SignUp
                retrieveDatabase={retrieveDatabase}
                user={user}
                registerUser={registerUser}
              />
            )
          }
        />
        <Route
          path="/profile"
          element={
            loggedIn ? (
              <Profile
                retrieveDatabase={retrieveDatabase}
                user={user}
                updateUser={updateUser}
                deleteUser={deleteUser}
                setLoggedIn={setLoggedIn}
                setTriggeredLogout={setTriggeredLogout}
              />
            ) : (
              <NotFound />
            )
          }
        />
        <Route path="*" element={<NotFound />} />
      </Routes>
      <Footer />
    </Router>
  );
}

import EdgyIcon from "../../assets/images/edgy-icon.png";
import { Link, useNavigate } from "react-router-dom";

const links = [
  { name: "About", href: "/about" },
  { name: "Pricing", href: "/pricing" },
  { name: "Blog", href: "/blog" },
  { name: "FAQ", href: "/faq" },
  { name: "Contact", href: "/contact" },
];

export default function Navigation({ loggedIn, setLoggedIn, setTriggeredLogout }) {
  const navigate = useNavigate()
  const ResetLocation = () => window.scrollTo(0, 0);
  const logOutUser = () => {
    setTriggeredLogout(true);
    setLoggedIn(false);
    navigate('/')
  }
  return (
    <header className="bg-gray-900">
      <nav className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8" aria-label="Top">
        <section className="w-full py-6 flex items-center justify-between border-b border-indigo-500 lg:border-none">
          <section className="flex items-center">
            <Link to="/" onClick={ResetLocation}>
              <span className="sr-only">Edgy</span>
              <img className="h-10 w-auto" src={EdgyIcon} alt="Edgy" />
            </Link>
            <section className="hidden ml-10 space-x-8 lg:block">
              {links.map((link) => (
                <Link
                  onClick={ResetLocation}
                  key={link.name}
                  to={link.href}
                  className="text-base font-medium text-white hover:text-indigo-50"
                >
                  {link.name}
                </Link>
              ))}
            </section>
          </section>
          {loggedIn ? <section className="ml-10 space-x-4">
            <button onClick={() => { logOutUser() }} className="inline-block bg-indigo-500 py-2 px-4 border border-transparent rounded-md text-base font-medium text-white hover:bg-opacity-75">
              Sign out
            </button>
            <Link onClick={ResetLocation} to="/profile" className="inline-block bg-white py-2 px-4 border border-transparent rounded-md text-base font-medium text-indigo-600 hover:bg-indigo-50">
              Profile
            </Link>
          </section> :
            <section className="ml-10 space-x-4">
              <Link onClick={ResetLocation} to="/sign-in" className="inline-block bg-indigo-500 py-2 px-4 border border-transparent rounded-md text-base font-medium text-white hover:bg-opacity-75">
                Sign in
              </Link>
              <Link onClick={ResetLocation} to="/sign-up" className="inline-block bg-white py-2 px-4 border border-transparent rounded-md text-base font-medium text-indigo-600 hover:bg-indigo-50">
                Sign up
              </Link>
            </section>}
        </section>
        <section className="py-4 flex flex-wrap justify-center space-x-6 lg:hidden">
          {links.map((link) => (
            <Link
              onClick={ResetLocation}
              key={link.name}
              to={link.href}
              className="text-base font-medium text-white hover:text-indigo-50"
            >
              {link.name}
            </Link>
          ))}
        </section>
      </nav>
    </header>
  );
}

