export const mswHandlers = [
  // Airtable server URL - returns user database
  http.get('**/api/airtable*', () =>
    HttpResponse.json({
      records: [
        {
          id: 'rec123',
          createdTime: '2024-01-15T10:00:00.000Z',
          fields: {
            id: 'user-1',
            email: 'demo@edgy.com',
            password: 'password123',
            fullname: 'Demo User',
            gender: 'other',
            plan: 'Premium',
