  args: {
    loggedIn: false,
    setLoggedIn: () => {},
    setTriggeredLogout: () => {},
  },
  play: async ({ canvas }) => {
    const header = canvas.getByRole('banner');
    // bg-gray-900 in Tailwind = rgb(17, 24, 39)
    await expect(getComputedStyle(header).backgroundColor).toBe('rgb(17, 24, 39)');
  },
});

