import preview from '../../../.storybook/preview';
import { expect } from 'storybook/test';
import Navigation from './Navigation';

const meta = preview.meta({
  component: Navigation,
  tags: ['ai-generated'],
});

export default meta;

export const LoggedOut = meta.story({
  args: {
    loggedIn: false,
    setLoggedIn: () => {},
    setTriggeredLogout: () => {},
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('link', { name: /about/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /pricing/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /sign in/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /sign up/i })).toBeVisible();
  },
});

export const LoggedIn = meta.story({
  args: {
    loggedIn: true,
    setLoggedIn: () => {},
    setTriggeredLogout: () => {},
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /sign out/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /profile/i })).toBeVisible();
  },
});

export const CssCheck = meta.story({
  args: {
    loggedIn: false,
    setLoggedIn: () => {},
    setTriggeredLogout: () => {},
  },
  play: async ({ canvas }) => {
    const header = canvas.getByRole('banner');
    const bgColor = getComputedStyle(header).backgroundColor;
    // bg-gray-900 should produce a dark gray background (not transparent/empty)
    await expect(bgColor).not.toBe('');
    await expect(bgColor).not.toBe('rgba(0, 0, 0, 0)');
    await expect(bgColor).not.toBe('transparent');
  },
});

